const body = $input.first().json.body || {};
let phone = (body.phone || '').replace(/\D/g, '');
if (phone.length >= 10 && !phone.startsWith('55')) {
  phone = '55' + phone;
}
const name = body.employeeName || 'Colaborador';
const confirmUrl = body.confirmUrl || '';
const ppeName = body.ppeName || '';
const caNumber = body.caNumber || 'N/A';
const quantity = body.quantity || 1;

const text = `🦺 *Novo Horizonte Alumínios - Confirmação de EPI*

Olá, ${name}!

O técnico de segurança registrou a entrega do seguinte EPI para você:

📦 *Item:* ${ppeName} (CA: ${caNumber})
🔢 *Quantidade:* ${quantity}

Para confirmar o recebimento do equipamento que seu líder irá lhe entregar, acesse o link abaixo e insira seu PIN:

🔗 *Acesse o link para assinar:*
${confirmUrl}

⏳ _Este link expira em 72 horas._

Em caso de dúvidas, procure o SESMT.`;

return [{ json: { number: phone, text } }];
